const express = require('express');
const bodyParser = require('body-parser');
const jwt = require('jsonwebtoken');
const redis = require('redis');
const crypto = require('crypto');

const app = express();
const client = redis.createClient();

const ACCESS_TOKEN_SECRET = 'your_access_token_secret';
const REFRESH_TOKEN_SECRET = 'your_refresh_token_secret';
const ACCESS_TOKEN_LIFETIME = '15m';
const REFRESH_TOKEN_LIFETIME = 365 * 24 * 60 * 60; // 1 year in seconds

app.use(bodyParser.json());

function generateAccessToken(user) {
  return jwt.sign(user, ACCESS_TOKEN_SECRET, { expiresIn: ACCESS_TOKEN_LIFETIME });
}

function generateRefreshToken(user) {
  const refreshToken = crypto.randomBytes(40).toString('hex');
  client.setex(refreshToken, REFRESH_TOKEN_LIFETIME, JSON.stringify(user));
  return refreshToken;
}

app.post('/token', (req, res) => {
  const { username, password } = req.body;
  // Authenticate user (this should be replaced with real authentication logic)
  if (username === 'user' && password === 'password') {
    const user = { username };
    const accessToken = generateAccessToken(user);
    const refreshToken = generateRefreshToken(user);
    res.json({ accessToken, refreshToken });
  } else {
    res.sendStatus(401);
  }
});

app.post('/token/refresh', (req, res) => {
  const { refreshToken } = req.body;
  if (!refreshToken) return res.sendStatus(401);

  client.get(refreshToken, (err, user) => {
    if (err || !user) return res.sendStatus(403);

    const accessToken = generateAccessToken(JSON.parse(user));
    res.json({ accessToken });
  });
});

